/** @typedef {import('../..').RightContent} RightContent */

/**
 * @param {import('react').ReactNode | undefined} slot
 * @param {Pick<import('../..').ListItemContentProps, 'title' | 'description' | 'rightContent'>} layoutProps
 * @param {{ legacyBehavior?: boolean }} options
 */
export const hasSlot = (slot, { title, description, rightContent }, { legacyBehavior = false }) => {
  const hasRightContent = typeof rightContent === 'object'
    ? /** @type {RightContent} */ (rightContent)?.content || /** @type {RightContent} */ (rightContent)?.description
    : rightContent;
  const hasDefaultContent = title || description || hasRightContent;
  const isSlotted = legacyBehavior ? (slot && !hasDefaultContent) : slot;

  return !!isSlotted;
};
