import { Children } from 'react';
import warning from '@andes/common/build/utils/warning';
import { hasSlot } from '../utils/hasSlot';
import computeRightContent from '../utils/computeRightContent';

/** @typedef {{ type: string; element: import('react').ReactNode }} ChildNodeItem */

/**
 * @typedef {Object} NativeProps
 * @prop {string} [`aria-label`]
 */

/** @typedef {import('../../index').ListItemProps} ListItemProps */

/** @param {ListItemProps} props */
const hasChildNodes = ({ title, children }) => title && Children.count(children) > 0;

/** @param {ListItemProps & NativeProps} props */
const itemNodeGenerator = function* getCollectionNode(props) {
  const {
    children,
    'aria-label': ariaLabel,
    title,
    description,
    rightContent,
  } = props;
  const rendered = title || children;
  const textValue = (typeof rendered === 'string' ? rendered : '') || ariaLabel || '';
  const isSlotted = hasSlot(
    children,
    {
      title,
      description,
      rightContent: computeRightContent({ rightContent })?.content,
    },
    { legacyBehavior: true },
  );

  warning(
    isSlotted || textValue,
    '<ListItem> needs some plain text contents for accessibility reasons. Please add a `title` or `aria-label` prop.',
  );

  yield {
    type: 'item',
    key: props.value,
    props,
    rendered,
    textValue,
    'aria-label': ariaLabel || title,
    hasChildNodes,
    * childNodes() {
      if (title) {
        /** @type {ChildNodeItem[]} */
        const items = [];

        Children.forEach(children, child => {
          items.push({ type: 'item', element: child });
        });

        yield* items;
      }
    },
  };
};

export default itemNodeGenerator;
